116			result.Set = make([]HTTPHeader, 0, len(filter.Set))
117			for _, s := range filter.Set {
118				result.Set = append(result.Set, HTTPHeader{Name: string(s.Name), Value: s.Value})
119			}
120		}
121	
122		if len(filter.Add) != 0 {
123			result.Add = make([]HTTPHeader, 0, len(filter.Add))
124			for _, a := range filter.Add {
125				result.Add = append(result.Add, HTTPHeader{Name: string(a.Name), Value: a.Value})
126			}
127		}
128	
129		return result
130	}
