245	func convertAuthenticationFilterOIDC(
246		filter *graph.AuthenticationFilter,
247		referencedSecrets map[types.NamespacedName]*secrets.Secret,
248	) *AuthOIDC {
249		if filter.Source.Spec.OIDC == nil {
250			return nil
251		}
252		specOIDC := filter.Source.Spec.OIDC
253	
254		referencedClientSecret, isReferenced := referencedSecrets[types.NamespacedName{
255			Namespace: filter.Source.Namespace,
256			Name:      specOIDC.ClientSecretRef.Name,
257		}]
258	
259		if !isReferenced || referencedClientSecret.Source == nil {
260			return nil
261		}
262	
263		providerName := fmt.Sprintf("%s_%s", filter.Source.Namespace, filter.Source.Name)
264	
265		redirectURI := fmt.Sprintf("%s_%s_%s", oidcCallBack, filter.Source.Namespace, filter.Source.Name)
266		if specOIDC.RedirectURI != nil {
267			redirectURI = *specOIDC.RedirectURI
268		}
269	
270		oidc := &OIDCProvider{
271			Name:         providerName,
272			Issuer:       specOIDC.Issuer,
273			ClientID:     specOIDC.ClientID,
274			ClientSecret: string(referencedClientSecret.Source.Data[secrets.ClientSecretKey]),
275			RedirectURI:  redirectURI,
276			ConfigURL:    specOIDC.ConfigURL,
277			PKCE:         specOIDC.PKCE,
278		}
279	
280		setOIDCCACert(oidc, specOIDC.CACertificateRefs, filter.Source.Namespace, referencedSecrets)
281	
282		if specOIDC.CRLSecretRef != nil {
283			setOIDCCRLCert(oidc, specOIDC.CRLSecretRef.Name, filter.Source.Namespace, referencedSecrets)
284		}
285	
286		oidc.ExtraAuthArgs = buildSortedExtraAuthArgs(specOIDC.ExtraAuthArgs)
287	
288		if specOIDC.Session != nil {
289			oidc.CookieName = specOIDC.Session.CookieName
290			if specOIDC.Session.Timeout != nil {
291				t := string(*specOIDC.Session.Timeout)
292				oidc.Timeout = &t
293			}
294		}
295	
296		if specOIDC.Logout != nil {
297			oidc.LogoutURI = specOIDC.Logout.URI
298			oidc.PostLogoutURI = specOIDC.Logout.PostLogoutURI
299			oidc.FrontChannelLogoutURI = specOIDC.Logout.FrontChannelLogoutURI
300			oidc.TokenHint = specOIDC.Logout.TokenHint
301		}
302	
303		result := &AuthOIDC{
304			Provider: oidc,
305		}
306	
307		// Populate authorization fields (auth_jwt_require + proxy_set_header) from the AuthZConfig
308		if specOIDC.Authorization != nil {
309			filterNsName := strings.Join([]string{filter.Source.Namespace, filter.Source.Name}, "_")
310			filterPrefix := sanitizeVariablePrefix(filterNsName)
311			authZConfig := buildAuthZConfigFromAuthZSpec(filterPrefix, specOIDC.Authorization)
312			if authZConfig != nil {
313				result.AuthRequireVariable = authZConfig.RequireVariable
314				result.AuthZProxySetHeaders = authZConfig.ProxySetHeaders
315			}
316		}
317	
318		return result
319	}
