321	func convertAuthenticationFilterJwtAuth(
322		filter *graph.AuthenticationFilter,
323		referencedSecrets map[types.NamespacedName]*secrets.Secret,
324	) *AuthJWT {
325		var result *AuthJWT
326		if specJWT := filter.Source.Spec.JWT; specJWT != nil {
327			if specJWT.Source == ngfAPI.JWTKeySourceFile && specJWT.File != nil {
328				// Handle File-based JWT (local JWKS)
329				referencedSecret, isReferenced := referencedSecrets[types.NamespacedName{
330					Namespace: filter.Source.Namespace,
331					Name:      specJWT.File.SecretRef.Name,
332				}]
333	
334				if isReferenced && referencedSecret.Source != nil {
335					result = &AuthJWT{
336						SecretName:      specJWT.File.SecretRef.Name,
337						SecretNamespace: referencedSecret.Source.Namespace,
338						Data:            referencedSecret.Source.Data[secrets.AuthKey],
339						Realm:           specJWT.Realm,
340						KeyCache:        specJWT.KeyCache,
341					}
342				}
343			} else if specJWT.Source == ngfAPI.JWTKeySourceRemote && specJWT.Remote != nil {
344				// Handle Remote JWT (remote JWKS)
345				remote := convertRemoteJWTJwtAuthFilter(specJWT, filter, referencedSecrets)
346	
347				result = &AuthJWT{
348					Realm:    specJWT.Realm,
349					KeyCache: specJWT.KeyCache,
350					Remote:   remote,
351				}
352			}
353	
354			// Populate authorization fields (auth_jwt_require + proxy_set_header) from the AuthZConfig
355			if result != nil {
356				result.Leeway = specJWT.Leeway
357				if specJWT.Authorization != nil {
358					filterNsName := strings.Join([]string{filter.Source.Namespace, filter.Source.Name}, "_")
359					filterPrefix := sanitizeVariablePrefix(filterNsName)
360					authZConfig := buildAuthZConfigFromAuthZSpec(filterPrefix, specJWT.Authorization)
361					if authZConfig != nil {
362						result.AuthRequireVariable = authZConfig.RequireVariable
363						result.AuthZProxySetHeaders = authZConfig.ProxySetHeaders
364					}
365				}
366			}
367		}
368	
369		return result
370	}
