372	func convertRemoteJWTJwtAuthFilter(
373		specJWT *ngfAPI.JWTAuth,
374		filter *graph.AuthenticationFilter,
375		referencedSecrets map[types.NamespacedName]*secrets.Secret,
376	) *AuthJWTRemote {
377		remote := &AuthJWTRemote{
378			URI: specJWT.Remote.URI,
379			Path: fmt.Sprintf(
380				"%s-%s_%s_jwks_uri",
381				http.InternalRoutePathPrefix,
382				filter.Source.Namespace,
383				filter.Source.Name,
384			),
385		}
386	
387		if len(specJWT.Remote.CACertificateRefs) > 0 {
388			for _, ref := range specJWT.Remote.CACertificateRefs {
389				referencedSecret, isReferenced := referencedSecrets[types.NamespacedName{
390					Namespace: filter.Source.Namespace,
391					Name:      ref.Name,
392				}]
393	
394				if isReferenced && referencedSecret.Source != nil && referencedSecret.Source.Data[secrets.CAKey] != nil {
395					remote.CACertBundlePath = generateJWTRemoteTLSCABundleID(filter.Source.Namespace, ref.Name)
396					break
397				}
398			}
399		}
400	
401		return remote
402	}
