507		routeNsName types.NamespacedName,
508		ruleIdx int,
509		gwNsName types.NamespacedName,
510	) *HTTPExternalAuthFilter {
511		if filter == nil {
512			return nil
513		}
514	
515		result := &HTTPExternalAuthFilter{
516			UpstreamName: resolvedBackendRef.ServicePortReference(),
517			InternalPath: generateExternalAuthInternalPath(routeNsName, ruleIdx),
518			VerifyTLS:    convertBackendTLS(resolvedBackendRef.BackendTLSPolicy, gwNsName),
519		}
520	
521		if filter.HTTPAuthConfig != nil {
522			result.PathPrefix = filter.HTTPAuthConfig.Path
523			result.AllowedRequestHeaders = filter.HTTPAuthConfig.AllowedRequestHeaders
524			result.AllowedResponseHeaders = filter.HTTPAuthConfig.AllowedResponseHeaders
525		}
526	
527		if filter.ForwardBody != nil && filter.ForwardBody.MaxSize > 0 {
528			result.ForwardBody = true
529			result.MaxBodySize = filter.ForwardBody.MaxSize
530		}
531	
532		return result
