535	func generateExternalAuthInternalPath(routeNsName types.NamespacedName, ruleIdx int) string {
536		return fmt.Sprintf("%s-ext-auth-%s_%s_rule%d",
537			http.InternalRoutePathPrefix, routeNsName.Namespace, routeNsName.Name, ruleIdx)
538	}
539	
540	func buildSortedExtraAuthArgs(extraAuthArgs map[string]string) string {
541		if len(extraAuthArgs) == 0 {
542			return ""
543		}
544		keys := make([]string, 0, len(extraAuthArgs))
545		for k := range extraAuthArgs {
546			keys = append(keys, k)
547		}
548		sort.Strings(keys)
549		pairs := make([]string, 0, len(keys))
550		for _, k := range keys {
551			pairs = append(pairs, k+"="+extraAuthArgs[k])
552		}
553		return strings.Join(pairs, "&")
554	}
